sys_script_include.script:
function CheckRecordData(grRecord)
{
	if (IsValidRecord(grRecord) == false)
	{
		return false;
	}

	return true;

	function Error(strText)
	{
		var strPayload = 'CheckRecordData: ' + strText;
		strPayload += '\n' + RenderValue(grRecord);
		strPayload += '\n\n' + RenderCallStack(GetCallStack());
		LogError(strPayload);
	}

	var strClassName = grRecord.getRecordClassName();

	if (IsTestSession() == true)
	{
		if (strClassName == 'sys_app')
		{

			if (grRecord.scope != 'global')
			{
				var strScope = GetStringValue(grRecord.scope);
				if (strScope.indexOf('x_test_') != 0)
				{
					Error('App scope name must start with "x_test_" during test execution.');
					return false;
				}
			}
			var strName = GetStringValue(grRecord.name);
			if (strName.indexOf('Test ') != 0)
			{
				Error('App names must start with "Test " during test execution.');
				return false;
			}
		}

		if (strClassName != 'sys_properties')
		{
			if (grRecord.sys_scope != 'global')
			{
				var grApp = GetAppRecord(grRecord.sys_scope);
				if (IsValidRecord(grApp) == true)
				{
					var strScope = GetStringValue(grApp.scope);
					if (strScope != 'global')
					{
						if (strScope.indexOf('x_test_') != 0)
						{
							Error('GlideRecordInsert: Metadata records must not be added to any scoped application where the scope name does not start with "x_test_" during test execution.');
							return false;
						}
					}					
				}

			}
		}
	}


	if (grRecord.getRecordClassName() == 'x_snc_devtools_dependency')
	{
		var grDevToolsApp = GetAppRecord('x_snc_devtools');
		if (grRecord.sys_scope == grDevToolsApp.sys_id)
		{
			Error('No one is allowed to add dependencies to DevTools');
			return false;
		}
	}
	if (grRecord.getRecordClassName() == 'sys_app')
	{
		if (GetStringValue(grRecord.scope) == '')
		{
			Error('App scope name must not be empty.');
			return false;
		}
	}


	if (IsDerivedFromTable(strClassName,'sys_metadata') == true)
	{
		if (grRecord.sys_scope == '')
		{
			Error('For a record derived from sys_metadata, sys_scope must not be empty!');
			return false;
		}
	}



	return true;
}
